// ═══════════════════════════════════════════════════════════════
// SPIKE HUNTER PRO v14 — MULTI-LAYER CONFLUENCE FILTER
// Hard Gates → Score → Confluence Count → Profit Estimation
// ═══════════════════════════════════════════════════════════════

const webhookData = $('Webhook Trigger').first().json.body;
const symbol = webhookData.symbol;
const wsPctChange = parseFloat(webhookData.priceChangePercent);
const wsDirection = webhookData.direction;
const dynamicThreshold = webhookData.threshold ? parseFloat(webhookData.threshold) : 2.0;
const nowTs = Date.now();

// ═══ LAYER 1: FRESHNESS CHECK ═══
const FRESHNESS_LIMIT_MS = 3 * 60 * 1000;
if (webhookData.triggeredAt) {
  const triggeredTs = new Date(webhookData.triggeredAt).getTime();
  const ageSec = Math.round((nowTs - triggeredTs) / 1000);
  if (nowTs - triggeredTs > FRESHNESS_LIMIT_MS) {
    return [{ json: { isHot: false, symbol, rejectReason: '\u23f0 STALE: Signal sudah ' + ageSec + 's (maks 180s).' } }];
  }
}

// ═══ LAYER 2: DEDUP + RATE LIMIT ═══
const DEDUP_WINDOW_MS = 3 * 60 * 60 * 1000;
const RATE_LIMIT_MS = 10 * 60 * 1000;
const SCORE_UPGRADE_THRESHOLD = 12;
const state = $getWorkflowStaticData('global');
if (!state.signalCache) state.signalCache = {};
for (const key of Object.keys(state.signalCache)) {
  if (nowTs - state.signalCache[key].ts > 6 * 60 * 60 * 1000) delete state.signalCache[key];
}
const dedupKey = symbol + '_' + wsDirection;
const lastEntry = state.signalCache[dedupKey];
if (lastEntry && (nowTs - lastEntry.ts < RATE_LIMIT_MS)) {
  return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udd04 RATE LIMIT: ' + symbol + ' sudah diproses ' + Math.round((nowTs - lastEntry.ts) / 60000) + 'm lalu.' } }];
}

// ═══ KLINES PARSING ═══
function parseKlines(nodeName) {
  let raw = $(nodeName).first().json;
  let data = Array.isArray(raw) ? raw : (typeof raw.data === 'string' ? JSON.parse(raw.data) : raw.data);
  if (!Array.isArray(data) || data.length < 20) return null;
  return {
    open:   data.map(function(k) { return parseFloat(k[1]); }),
    high:   data.map(function(k) { return parseFloat(k[2]); }),
    low:    data.map(function(k) { return parseFloat(k[3]); }),
    close:  data.map(function(k) { return parseFloat(k[4]); }),
    volume: data.map(function(k) { return parseFloat(k[5]); }),
  };
}

const tf1h = parseKlines('Get Klines 1h');
const tf4h = parseKlines('Get Klines 4h');
if (!tf1h) return [{ json: { isHot: false, symbol, rejectReason: 'Data klines 1H tidak cukup' } }];

// ═══ INDICATOR FUNCTIONS ═══
function calcEMA(p, n) {
  const k = 2/(n+1); let e = p.slice(0,n).reduce(function(a,b){return a+b;})/n;
  const r = new Array(n-1).fill(null); r.push(e);
  for (let i=n; i<p.length; i++) { e=(p[i]-e)*k+e; r.push(e); }
  return r;
}
function calcRSI(p, n) {
  n = n || 14;
  if (p.length < n+1) return 50;
  let g=0,lo=0;
  for (let i=1; i<=n; i++) { let d=p[i]-p[i-1]; d>=0?g+=d:lo-=d; }
  let ag=g/n, al=lo/n;
  for (let i=n+1; i<p.length; i++) {
    let d=p[i]-p[i-1]; ag=((ag*(n-1))+(d>=0?d:0))/n; al=((al*(n-1))+(d<0?-d:0))/n;
  }
  return al===0 ? 100 : 100-(100/(1+(ag/al)));
}
function calcMACD(p) {
  const f=calcEMA(p,12), s=calcEMA(p,26), ml=[];
  for (let i=0; i<p.length; i++) if(f[i]!==null&&s[i]!==null) ml.push(f[i]-s[i]);
  if (ml.length<9) return {h:0,ph:0,cu:false,cd:false,hist:0};
  const sl=calcEMA(ml,9);
  const lm=ml[ml.length-1],ls=sl[sl.length-1]||0,pm=ml[ml.length-2]||lm,ps=sl[sl.length-2]||ls;
  return {h:lm-ls, ph:pm-ps, cu:pm<=ps&&lm>ls, cd:pm>=ps&&lm<ls, hist:lm-ls};
}
function calcATR(h,l,c,n) {
  n=n||14; if(h.length<n+1) return 0;
  let t=[h[0]-l[0]];
  for(let i=1;i<h.length;i++) t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
  let a=t.slice(0,n).reduce(function(x,y){return x+y;})/n;
  for(let i=n;i<t.length;i++) a=(a*(n-1)+t[i])/n;
  return a;
}
function calcADX(h,l,c,n) {
  n=n||14; if(h.length<n*3) return 0;
  let t=[],pd=[],md=[];
  for(let i=1;i<h.length;i++) {
    t.push(Math.max(h[i]-l[i],Math.abs(h[i]-c[i-1]),Math.abs(l[i]-c[i-1])));
    let u=h[i]-h[i-1],d=l[i-1]-l[i];
    pd.push(u>d&&u>0?u:0); md.push(d>u&&d>0?d:0);
  }
  let aT=t.slice(0,n).reduce(function(a,b){return a+b;}),aP=pd.slice(0,n).reduce(function(a,b){return a+b;}),aM=md.slice(0,n).reduce(function(a,b){return a+b;});
  const dx=[];
  for(let i=n;i<t.length;i++) {
    aT=aT-aT/n+t[i]; aP=aP-aP/n+pd[i]; aM=aM-aM/n+md[i];
    let pI=(aP/aT)*100,mI=(aM/aT)*100;
    dx.push((pI+mI)===0?0:Math.abs(pI-mI)/(pI+mI)*100);
  }
  if(dx.length<n) return 0;
  let a=dx.slice(0,n).reduce(function(x,y){return x+y;})/n;
  for(let i=n;i<dx.length;i++) a=((a*(n-1))+dx[i])/n;
  return a;
}

// ═══ 4H TREND ANALYSIS ═══
let trend4h = 'SIDEWAYS';
let rsi4h = 50;
let trend4hBias = 'NEUTRAL';
let res4h = 0;
if (tf4h) {
  const c4 = tf4h.close, h4 = tf4h.high;
  const e21_4h = calcEMA(c4, 21);
  const e50_4h = calcEMA(c4, 50);
  const price4h = c4[c4.length - 1];
  const E21_4h = e21_4h[e21_4h.length-1] || price4h;
  const E50_4h = e50_4h[e50_4h.length-1] || price4h;
  rsi4h = calcRSI(c4);
  res4h = Math.max.apply(null, h4.slice(-90));
  if (price4h > E21_4h && E21_4h > E50_4h) { trend4h = 'UPTREND'; trend4hBias = 'BULLISH'; }
  else if (price4h < E21_4h && E21_4h < E50_4h) { trend4h = 'DOWNTREND'; trend4hBias = 'BEARISH'; }
}

// ═══ 1H INDICATORS ═══
const c = tf1h.close, h = tf1h.high, l = tf1h.low, o = tf1h.open, v = tf1h.volume;
const price = c[c.length - 1];
const idx = c.length - 1;
const _rsi = calcRSI(c);
const _prevRsi = calcRSI(c.slice(0, -1));
const _macd = calcMACD(c);
const _atr = calcATR(h, l, c);
const _adx = calcADX(h, l, c);
const e21 = calcEMA(c, 21), e50 = calcEMA(c, 50), e200 = calcEMA(c, 200);
const E21 = e21[e21.length-1]||price, E50 = e50[e50.length-1]||price, E200 = e200[e200.length-1]||price;
const avgVol = v.slice(-20).reduce(function(a,b){return a+b;})/20;
const volRatio = v[v.length-1]/avgVol;
const res1h = Math.max.apply(null, h.slice(-200));
const recentL = Math.min.apply(null, l.slice(-200));
const effectiveRes = (res4h > 0 && Math.abs(res4h - res1h) / price < 0.05)
  ? Math.max(res4h, res1h) : (res4h > 0 ? Math.min(res4h, res1h) : res1h);
let trend = 'SIDEWAYS';
if(price>E21&&E21>E50) trend = 'UPTREND';
else if(price<E21&&E21<E50) trend = 'DOWNTREND';
const body = Math.abs(c[idx] - o[idx]);
const range = h[idx] - l[idx];
const upperWick = h[idx] - Math.max(c[idx], o[idx]);
const lowerWick = Math.min(c[idx], o[idx]) - l[idx];
const bodyRatio = range > 0 ? body / range : 0;
const isGreen = c[idx] > o[idx];
const isRed = c[idx] < o[idx];

// Volume vs 5-bar avg (for breakout)
const vol5avg = v.slice(Math.max(0, idx-5), idx).reduce(function(a,b){return a+b;}, 0) / Math.min(5, idx);
const volBreakRatio = vol5avg > 0 ? v[idx] / vol5avg : 1;

// Freefall detection
let ffCount = 0;
for (let k = idx-5; k <= idx; k++) {
  if (k > 24) { const ll = Math.min.apply(null, l.slice(k-24, k)); if (l[k] < ll) ffCount++; }
}

let score = 0, signal = 'NEUTRAL', strategy = 'WAIT', confidence = 'LOW';
const reasons = [];
let confluenceCount = 0;
let confluenceTotal = 7;
let estimatedTP1Pct = 0, estimatedTP2Pct = 0, estimatedTP3Pct = 0, estimatedRiskPct = 0;

// ═══════════════════════════════════════════════════════════════
// STRATEGY 1: BUY THE DIP (LONG on crash)
// ═══════════════════════════════════════════════════════════════
if (wsPctChange <= -dynamicThreshold) {

  // ── HARD GATES ──
  if (_rsi >= 40) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: RSI ' + _rsi.toFixed(0) + ' tidak oversold (<40)' } }];
  }
  if (ffCount >= 3) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: FREEFALL terdeteksi (' + ffCount + ' break low)' } }];
  }
  if (!isGreen) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: Candle merah — tunggu konfirmasi hijau. RSI: ' + _rsi.toFixed(0) } }];
  }
  if (volRatio < 1.5) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: Volume rendah (' + volRatio.toFixed(1) + 'x) — butuh min 1.5x' } }];
  }
  if (trend4hBias === 'BEARISH') {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: 4H DOWNTREND — tidak LONG melawan tren besar' } }];
  }
  if (_rsi > _prevRsi === false && _rsi >= 25) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab GATE: RSI ' + _rsi.toFixed(0) + ' masih turun (belum reversal)' } }];
  }

  // ── SCORING ──
  // 1. RSI Oversold (max 25)
  if (_rsi < 20) { score += 25; reasons.push('RSI ' + _rsi.toFixed(0) + ' extreme \ud83d\udd25'); confluenceCount++; }
  else if (_rsi < 25) { score += 20; reasons.push('RSI ' + _rsi.toFixed(0) + ' deep oversold'); confluenceCount++; }
  else if (_rsi < 30) { score += 15; reasons.push('RSI ' + _rsi.toFixed(0) + ' oversold'); confluenceCount++; }
  else if (_rsi < 35) { score += 10; reasons.push('RSI ' + _rsi.toFixed(0)); confluenceCount++; }
  else { score += 5; }

  // 2. Drop Magnitude (max 15)
  const absPct = Math.abs(wsPctChange);
  if (absPct >= 10) { score += 15; reasons.push(absPct.toFixed(1) + '% CRASH \ud83d\udca5'); confluenceCount++; }
  else if (absPct >= 7) { score += 12; reasons.push(absPct.toFixed(1) + '% big drop'); confluenceCount++; }
  else if (absPct >= 5) { score += 9; reasons.push(absPct.toFixed(1) + '% drop'); confluenceCount++; }
  else if (absPct >= 3) { score += 6; reasons.push(absPct.toFixed(1) + '% dip'); }
  else { score += 3; }

  // 3. Volume Spike (max 12) — already passed gate > 1.5x
  if (volRatio > 4.0) { score += 12; reasons.push('Vol ' + volRatio.toFixed(1) + 'x MASSIVE'); confluenceCount++; }
  else if (volRatio > 2.5) { score += 8; reasons.push('Vol ' + volRatio.toFixed(1) + 'x spike'); confluenceCount++; }
  else { score += 4; reasons.push('Vol ' + volRatio.toFixed(1) + 'x'); }

  // 4. Green Candle Quality (max 15) — already passed gate: isGreen
  if (bodyRatio > 0.6) { score += 15; reasons.push('Marubozu (' + (bodyRatio*100).toFixed(0) + '% body) \u2705'); confluenceCount++; }
  else if (bodyRatio > 0.4) { score += 10; reasons.push('Strong green (' + (bodyRatio*100).toFixed(0) + '%)'); confluenceCount++; }
  else { score += 5; reasons.push('Weak green (' + (bodyRatio*100).toFixed(0) + '%)'); }

  // 5. MACD (max 12)
  if (_macd.cu) { score += 12; reasons.push('MACD Bull Cross \ud83d\udd25'); confluenceCount++; }
  else if (_macd.h < 0 && _macd.h > _macd.ph) { score += 7; reasons.push('MACD turning up'); confluenceCount++; }
  else { reasons.push('MACD belum confirm'); }

  // 6. Support Level (max 12)
  const sup = Math.min.apply(null, l.slice(Math.max(0, idx-168), idx));
  const dSup = (price - sup) / price * 100;
  if (dSup < 0.5) { score += 12; reasons.push('Double Bottom \u2705'); confluenceCount++; }
  else if (dSup < 1.5) { score += 7; reasons.push('Near support (' + dSup.toFixed(1) + '%)'); confluenceCount++; }
  else if (dSup < 3) { score += 3; }

  // 7. Lower Wick rejection (max 7)
  if (range > 0 && lowerWick/range > 0.5) { score += 7; reasons.push('Buyer wick \u2191'); }
  else if (range > 0 && lowerWick/range > 0.3) { score += 4; }

  // 8. ADX (max 5)
  if (_adx < 20) { score += 5; reasons.push('ADX weak — mean revert ready'); }
  else if (_adx > 40) { score -= 5; reasons.push('ADX strong trend \u26a0\ufe0f'); }

  // 9. 4H Trend bonus (already passed BEARISH gate)
  if (trend4hBias === 'BULLISH') { score += 10; reasons.push('4H UPTREND \u2705 aligned'); }
  else { score += 3; reasons.push('4H Sideways'); }

  // ── CONFLUENCE CHECK ──
  if (confluenceCount < 4) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udeab CONFLUENCE: Hanya ' + confluenceCount + '/7 konfirmasi (min 4). Score ' + score } }];
  }

  // ── SIGNAL CLASSIFICATION ──
  if (score >= 75) { signal = 'STRONG BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'VERY HIGH'; }
  else if (score >= 65) { signal = 'STRONG BUY'; strategy = 'LONG (Buy Dip)'; confidence = 'HIGH'; }
  else { reasons.push('Score ' + score + ' belum cukup (min 65)'); }
}

// ═══════════════════════════════════════════════════════════════
// STRATEGY 2 & 3: PUMP SCENARIOS (SHORT or BREAKOUT)
// ═══════════════════════════════════════════════════════════════
else if (wsPctChange >= dynamicThreshold) {
  let shortScore = 0, breakoutScore = 0;
  const shortReasons = [], breakoutReasons = [];
  let shortConfluence = 0, breakoutConfluence = 0;

  // ══════ SHORT: Overbought Mean Reversion ══════
  // Hard Gates for SHORT
  const shortGatePass = (_rsi >= 65) && isRed && (trend4hBias !== 'BULLISH');

  if (shortGatePass) {
    // 1. RSI Overbought (max 25)
    if (_rsi >= 80) { shortScore += 25; shortReasons.push('RSI ' + _rsi.toFixed(0) + ' EXTREME OB \ud83d\udd25'); shortConfluence++; }
    else if (_rsi >= 75) { shortScore += 20; shortReasons.push('RSI ' + _rsi.toFixed(0) + ' overbought'); shortConfluence++; }
    else if (_rsi >= 70) { shortScore += 15; shortReasons.push('RSI ' + _rsi.toFixed(0) + ' high'); shortConfluence++; }
    else { shortScore += 8; shortReasons.push('RSI ' + _rsi.toFixed(0)); shortConfluence++; }

    // 2. Pump Magnitude (max 15)
    if (wsPctChange >= 12) { shortScore += 15; shortReasons.push('MASSIVE Pump ' + wsPctChange.toFixed(1) + '%'); shortConfluence++; }
    else if (wsPctChange >= 8) { shortScore += 12; shortReasons.push('Big Pump ' + wsPctChange.toFixed(1) + '%'); shortConfluence++; }
    else if (wsPctChange >= 5) { shortScore += 8; shortReasons.push('Pump ' + wsPctChange.toFixed(1) + '%'); shortConfluence++; }
    else { shortScore += 4; }

    // 3. Red Reversal Candle (max 15) — already gate passed
    if (bodyRatio > 0.5) { shortScore += 15; shortReasons.push('Strong reversal candle'); shortConfluence++; }
    else { shortScore += 8; shortReasons.push('Red candle'); shortConfluence++; }

    // 4. Upper Wick rejection (max 12)
    if (range > 0 && upperWick/range > 0.5) { shortScore += 12; shortReasons.push('Long upper wick (rejection)'); shortConfluence++; }
    else if (range > 0 && upperWick/range > 0.3) { shortScore += 7; shortReasons.push('Upper wick'); shortConfluence++; }

    // 5. MACD (max 12)
    if (_macd.cd) { shortScore += 12; shortReasons.push('MACD Bear Cross \ud83d\udd25'); shortConfluence++; }
    else if (_macd.h > 0 && _macd.h < _macd.ph) { shortScore += 6; shortReasons.push('MACD fading'); shortConfluence++; }

    // 6. Near Resistance (max 10)
    const dResShort = (effectiveRes - price) / price * 100;
    if (dResShort > -0.5 && dResShort < 1.0) { shortScore += 10; shortReasons.push('At MTF Resistance'); shortConfluence++; }

    // 7. 4H Bias
    if (trend4hBias === 'BEARISH') { shortScore += 10; shortReasons.push('4H DOWNTREND \u2705'); }
    else { shortScore += 3; shortReasons.push('4H Sideways'); }
  }

  // ══════ BREAKOUT LONG ══════
  // Hard Gates for BREAKOUT
  const dRes1hBreak = (price - res1h) / price * 100;
  const breakoutGatePass = (dRes1hBreak > 0 || (res4h > 0 && price > res4h))
    && volBreakRatio > 1.5
    && trend4hBias !== 'BEARISH'
    && (range > 0 && upperWick/range < 0.5);

  if (breakoutGatePass) {
    // 1. Multi-bar confirmation (check if previous candle also closed above)
    const prevAboveRes = idx > 0 && c[idx-1] > res1h;
    if (prevAboveRes) { breakoutScore += 20; breakoutReasons.push('2-bar close above res \ud83d\udd11'); breakoutConfluence++; }
    else { breakoutScore += 10; breakoutReasons.push('1-bar breakout'); breakoutConfluence++; }

    // 2. Volume (max 20)
    if (volBreakRatio > 3.0) { breakoutScore += 20; breakoutReasons.push('Vol BREAKOUT ' + volBreakRatio.toFixed(1) + 'x \ud83d\udd25'); breakoutConfluence++; }
    else if (volBreakRatio > 2.0) { breakoutScore += 14; breakoutReasons.push('Vol ' + volBreakRatio.toFixed(1) + 'x'); breakoutConfluence++; }
    else { breakoutScore += 8; breakoutReasons.push('Vol ' + volBreakRatio.toFixed(1) + 'x'); breakoutConfluence++; }

    // 3. RSI Momentum (max 15)
    if (_rsi >= 55 && _rsi < 70) { breakoutScore += 15; breakoutReasons.push('RSI Momentum ' + _rsi.toFixed(0)); breakoutConfluence++; }
    else if (_rsi >= 50 && _rsi < 55) { breakoutScore += 8; breakoutReasons.push('RSI ' + _rsi.toFixed(0)); breakoutConfluence++; }
    else if (_rsi >= 70) { breakoutScore += 5; breakoutReasons.push('RSI high ' + _rsi.toFixed(0) + ' \u26a0\ufe0f'); }
    else { breakoutScore -= 5; breakoutReasons.push('RSI weak ' + _rsi.toFixed(0)); }

    // 4. Candle Body (max 15)
    if (isGreen && bodyRatio > 0.75) { breakoutScore += 15; breakoutReasons.push('Marubozu (' + (bodyRatio*100).toFixed(0) + '%)'); breakoutConfluence++; }
    else if (isGreen && bodyRatio > 0.55) { breakoutScore += 8; breakoutReasons.push('Bullish (' + (bodyRatio*100).toFixed(0) + '%)'); breakoutConfluence++; }
    else if (bodyRatio < 0.3) { breakoutScore -= 10; breakoutReasons.push('Weak candle \u26a0\ufe0f'); }

    // 5. Fakeout Filter
    if (range > 0) {
      const wickR = upperWick / range;
      if (wickR < 0.15) { breakoutScore += 5; breakoutReasons.push('Clean breakout'); }
      else if (wickR > 0.35) { breakoutScore -= 8; breakoutReasons.push('Upper wick risk (' + (wickR*100).toFixed(0) + '%)'); }
    }

    // 6. 4H Resistance breakout
    const dRes4hBreak = res4h > 0 ? (price - res4h) / price * 100 : null;
    if (dRes4hBreak !== null && dRes4hBreak > 0 && dRes4hBreak < 3.0) {
      breakoutScore += 18; breakoutReasons.push('4H Res BREAK (+' + dRes4hBreak.toFixed(2) + '%) \ud83d\udd11'); breakoutConfluence++;
    } else if (dRes1hBreak > 0 && dRes1hBreak < 2.0) {
      breakoutScore += 12; breakoutReasons.push('1H Res break (+' + dRes1hBreak.toFixed(2) + '%)'); breakoutConfluence++;
    }

    // 7. MACD
    if (_macd.cu) { breakoutScore += 10; breakoutReasons.push('MACD Bull Cross'); breakoutConfluence++; }
    else if (_macd.h > 0 && _macd.h > _macd.ph) { breakoutScore += 7; breakoutReasons.push('MACD momentum \u2191'); breakoutConfluence++; }

    // 8. ADX
    if (_adx > 30) { breakoutScore += 10; breakoutReasons.push('ADX Strong (' + _adx.toFixed(0) + ')'); }
    else if (_adx > 25) { breakoutScore += 6; }
    else if (_adx < 15) { breakoutScore -= 8; breakoutReasons.push('ADX lemah'); }

    // 9. 4H Bias
    if (trend4hBias === 'BULLISH') { breakoutScore += 12; breakoutReasons.push('4H UPTREND \u2705'); }
    else { breakoutScore += 3; }
  }

  // ══════ DECIDE WINNER ══════
  // Check confluence for winner
  const shortConfluenceOk = shortConfluence >= 4;
  const breakoutConfluenceOk = breakoutConfluence >= 4;

  if (shortGatePass && shortConfluenceOk && shortScore >= 65 && shortScore >= breakoutScore) {
    score = shortScore; confluenceCount = shortConfluence; confluenceTotal = 7;
    reasons.push.apply(reasons, shortReasons);
    if (score >= 75) { signal = 'STRONG SELL'; strategy = 'SHORT (Overbought)'; confidence = 'VERY HIGH'; }
    else { signal = 'STRONG SELL'; strategy = 'SHORT (Overbought)'; confidence = 'HIGH'; }
  } else if (breakoutGatePass && breakoutConfluenceOk && breakoutScore >= 65) {
    score = breakoutScore; confluenceCount = breakoutConfluence; confluenceTotal = 7;
    reasons.push.apply(reasons, breakoutReasons);
    if (score >= 75) { signal = 'STRONG BUY'; strategy = 'LONG (Breakout)'; confidence = 'VERY HIGH'; }
    else { signal = 'STRONG BUY'; strategy = 'LONG (Breakout)'; confidence = 'HIGH'; }
  } else {
    // Neither passed
    const whyNot = [];
    if (shortGatePass) whyNot.push('SHORT score ' + shortScore + ' conf ' + shortConfluence + '/4');
    else whyNot.push('SHORT gates failed');
    if (breakoutGatePass) whyNot.push('BREAK score ' + breakoutScore + ' conf ' + breakoutConfluence + '/4');
    else whyNot.push('BREAK gates failed');
    reasons.push('Pump ' + wsPctChange.toFixed(1) + '% — ' + whyNot.join(' | '));
  }
} else {
  reasons.push('Change ' + wsPctChange.toFixed(1) + '% di bawah threshold ' + dynamicThreshold + '%');
}

// ═══ SL/TP CALCULATION + PROFIT ESTIMATION ═══
let sl = 0, tp1 = 0, tp2 = 0, tp3 = 0, riskPct = '0';
const isStrongSignal = signal === 'STRONG BUY' || signal === 'STRONG SELL';

if (_atr > 0 && isStrongSignal) {
  if (strategy.indexOf('LONG') !== -1) {
    sl = price - (_atr * 2.0);
    const slDist = price - sl;
    const meanDist = Math.max(E21 - price, _atr * 2);
    tp1 = price + Math.max(meanDist * 0.4, slDist * 1.5);
    tp2 = price + Math.max(meanDist * 0.7, slDist * 2.5);
    tp3 = price + Math.max(meanDist * 1.0, slDist * 3.5);
    riskPct = ((slDist / price) * 100).toFixed(2);
    estimatedTP1Pct = ((tp1 - price) / price * 100);
    estimatedTP2Pct = ((tp2 - price) / price * 100);
    estimatedTP3Pct = ((tp3 - price) / price * 100);
    estimatedRiskPct = ((price - sl) / price * 100);
  } else if (strategy.indexOf('SHORT') !== -1) {
    sl = price + (_atr * 2.0);
    const slDist = sl - price;
    const meanDist = Math.max(price - E21, _atr * 2);
    tp1 = price - Math.max(meanDist * 0.4, slDist * 1.5);
    tp2 = price - Math.max(meanDist * 0.7, slDist * 2.5);
    tp3 = price - Math.max(meanDist * 1.0, slDist * 3.5);
    riskPct = ((slDist / price) * 100).toFixed(2);
    estimatedTP1Pct = ((price - tp1) / price * 100);
    estimatedTP2Pct = ((price - tp2) / price * 100);
    estimatedTP3Pct = ((price - tp3) / price * 100);
    estimatedRiskPct = ((sl - price) / price * 100);
  }
}

// ═══ LAYER FINAL: DEDUP CHECK ═══
if (isStrongSignal && lastEntry && (nowTs - lastEntry.ts < DEDUP_WINDOW_MS)) {
  const scoreDiff = score - lastEntry.score;
  const elapsedMin = Math.round((nowTs - lastEntry.ts) / 60000);
  if (scoreDiff < SCORE_UPGRADE_THRESHOLD) {
    return [{ json: { isHot: false, symbol, rejectReason: '\ud83d\udd01 DEDUP: ' + wsDirection + ' ' + symbol + ' sent ' + elapsedMin + 'm ago (score ' + lastEntry.score + '→' + score + '). Need +' + SCORE_UPGRADE_THRESHOLD + ' to upgrade.' } }];
  }
}
if (isStrongSignal) { state.signalCache[dedupKey] = { ts: nowTs, score, signal }; }

return [{
  json: {
    symbol, price: price.toFixed(4),
    wsChange: wsPctChange.toFixed(2) + '%', wsDirection,
    signal, strategy, confidence, score,
    confluenceCount: confluenceCount + '/' + confluenceTotal,
    reasons: reasons.join(' | '),
    trend1h: trend, trend4h,
    ema21: E21.toFixed(4), ema200: E200.toFixed(4),
    macroTrend: price > E200 ? 'ABOVE MA200' : 'BELOW MA200',
    rsi1h: _rsi.toFixed(1), rsi4h: rsi4h.toFixed(1),
    macdHist: _macd.hist.toFixed(6),
    macdCross: _macd.cu ? 'BULL CROSS' : (_macd.cd ? 'BEAR CROSS' : 'None'),
    adx1h: _adx.toFixed(1), volRatio: volRatio.toFixed(1) + 'x',
    volBreakRatio: volBreakRatio.toFixed(1) + 'x vs 5bar',
    res1h: res1h.toFixed(4), res4h: res4h > 0 ? res4h.toFixed(4) : 'N/A',
    support: recentL.toFixed(4), resistance: effectiveRes.toFixed(4),
    distSupport: ((price - recentL) / price * 100).toFixed(2) + '%',
    distResistance: ((effectiveRes - price) / price * 100).toFixed(2) + '%',
    sl: sl.toFixed(4), tp1: tp1.toFixed(4), tp2: tp2.toFixed(4), tp3: tp3.toFixed(4),
    riskPct: riskPct + '%', atr: _atr.toFixed(6),
    estTP1: '+' + estimatedTP1Pct.toFixed(2) + '%',
    estTP2: '+' + estimatedTP2Pct.toFixed(2) + '%',
    estTP3: '+' + estimatedTP3Pct.toFixed(2) + '%',
    estRisk: '-' + estimatedRiskPct.toFixed(2) + '%',
    estRR1: '1:' + (estimatedTP1Pct / (estimatedRiskPct || 1)).toFixed(1),
    estRR2: '1:' + (estimatedTP2Pct / (estimatedRiskPct || 1)).toFixed(1),
    estRR3: '1:' + (estimatedTP3Pct / (estimatedRiskPct || 1)).toFixed(1),
    isHot: isStrongSignal,
    rejectReason: !isStrongSignal ? 'Score ' + score + '/100 (Min 65). ' + reasons.join(', ') : '',
  }
}];

